#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Durable auto-wire (exit-0-safe): transition APPROVED->WIRED, install a recurring
auto-wire timer + ensure the generic Socrata collector timer runs, so discovery-approved
sources connect + ingest CONTINUOUSLY (10+/day). Verifies catalog + business counts.
Robust publish (many retries)."""
import os,sys,json,time,subprocess
def sh(c,t=60):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "TO/ERR"
def psql(q,t=20):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR:"+r.stderr.strip()[:80])
out={"kind":"autowire","ts":int(time.time())}
try:
    out["states_now"]=psql("SELECT state||':'||count(*) FROM atlas.source_catalog GROUP BY state ORDER BY 2 DESC")
    out["business_total"]=psql("SELECT count(*) FROM atlas.business")
    out["wired_total"]=psql("SELECT count(*) FROM atlas.source_catalog WHERE state='WIRED'")
    # idempotent: approve->wired
    psql("UPDATE atlas.source_catalog SET state='WIRED', last_state_at=now() WHERE state='APPROVED'")
    # install auto-wire script + timer
    open("/opt/atlas/atlas_autowire.sh","w").write(
        "#!/bin/bash\n"
        "sudo -u postgres psql tuanichat_atlas -c \"UPDATE atlas.source_catalog SET state='WIRED', last_state_at=now() WHERE state='APPROVED'\" 2>/dev/null\n"
        "systemctl start --no-block atlas-socrata-generic.service 2>/dev/null\n")
    os.chmod("/opt/atlas/atlas_autowire.sh",0o755)
    open("/etc/systemd/system/atlas-autowire.service","w").write(
        "[Unit]\nDescription=ATLAS auto-wire approved discovery sources -> ingest\n[Service]\nType=oneshot\nExecStart=/opt/atlas/atlas_autowire.sh\n")
    open("/etc/systemd/system/atlas-autowire.timer","w").write(
        "[Unit]\nDescription=ATLAS auto-wire timer (every 10min)\n[Timer]\nOnBootSec=120\nOnUnitInactiveSec=600\nUnit=atlas-autowire.service\n[Install]\nWantedBy=timers.target\n")
    out["reload"]=sh("systemctl daemon-reload 2>&1; echo rc=$?")
    out["enable_autowire"]=sh("systemctl enable --now atlas-autowire.timer 2>&1 | tail -1; systemctl is-active atlas-autowire.timer")
    out["enable_generic"]=sh("systemctl enable --now atlas-socrata-generic.timer 2>&1 | tail -1; systemctl is-active atlas-socrata-generic.timer 2>/dev/null")
    out["ensure_disc_timer"]=sh("systemctl enable --now atlas-source-discovery.timer 2>&1 | tail -1; systemctl is-active atlas-source-discovery.timer 2>/dev/null")
    out["states_after"]=psql("SELECT state||':'||count(*) FROM atlas.source_catalog GROUP BY state ORDER BY 2 DESC")
    out["socrata_sources_live"]=psql("SELECT count(DISTINCT source_code) FROM atlas.source_record WHERE source_code LIKE 'socrata_%'") if psql("SELECT count(*) FROM information_schema.tables WHERE table_schema='atlas' AND table_name='source_record'")=='1' else 'n/a'
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error,random
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/autowire.json"%repo; sha=None
    if tok:
        for _ in range(15):
            try:
                try:
                    r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=15)).get("sha")
                except Exception: sha=None
                body={"message":"autowire","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
                if sha: body["sha"]=sha
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=20); break
            except Exception: time.sleep(0.5+random.random()*2)
except Exception: pass
sys.exit(0)
